const a=[{tag:"Institucional · 2026",title:"Gobierno y empresas: la ZAC como caso de éxito en San Luis",excerpt:"Alejandro Gómez, director ejecutivo de Coraza, destacó el acompañamiento del Gobierno provincial al sector privado y la expansión del polo comercial que ya reúne a más de 20 empresas en la zona sur de la ciudad.",date:"18 Marzo 2026",sortDate:"2026-03-18",img:"https://agenciasanluis.com/wp-content/uploads/2026/03/1.jpg.jpeg",url:"https://agenciasanluis.com/2026/03/18/1149637-este-gobierno-tiene-una-cercania-a-las-empresas-privadas/",source:"Agencia San Luis"},{tag:"Gastronomía · 2026",title:"ZAC amplía su propuesta y estrena el Patio de Sabores con nuevas marcas",excerpt:"Seis nuevos locales —Café Puntano, Lo de Filippo, Club de la Pizza, Charlie's Candy, Casa Ceh y Toyota Alianz— se suman al polo comercial en un espacio que funcionará todos los días con horarios extendidos.",date:"16 Enero 2026",sortDate:"2026-01-16",img:"https://vm24noticias.com.ar/wp-content/uploads/2026/01/Captura-de-pantalla-2026-01-15-174013-780x470.png",url:"https://vm24noticias.com.ar/zac-amplia-su-propuesta-y-estrena-el-patio-de-sabores-con-nuevas-marcas/",source:"VM 24 Noticias"},{tag:"Economía · 2026",title:"ZAC crece: el empuje del sector privado que impulsa la economía puntana",excerpt:"El análisis del impacto económico del polo comercial: más marcas, más servicios y más gastronomía en un mismo predio significan más empleo, más circulación de dinero y más actividad privada real en San Luis.",date:"13 Enero 2026",sortDate:"2026-01-13",img:"https://depolitica.com.ar/wp-content/uploads/2026/01/ZAC-2.jpeg",url:"https://depolitica.com.ar/zac-expansion-sector-privado-san-luis/",source:"DePolítica"},{tag:"Inversión · 2025",title:"Carrefour abrió su tienda Maxi en San Luis y suma 104 nuevos puestos de trabajo",excerpt:"La cadena de supermercados inauguró su sucursal número 35 del formato mayorista en el país, ubicada dentro de la ZAC. El local cuenta con 3.300 m² de salón, 165 lugares de estacionamiento y una inversión conjunta de más de $15.000 millones.",date:"16 Octubre 2025",sortDate:"2025-10-16",img:"https://pxbcdn.eldiariodelarepublica.com/republica/102025/1760658080267.webp?cw=770&ch=440&extw=jpg",url:"https://www.eldiariodelarepublica.com/nota/2025-10-16-20-27-0-carrefour-abrio-su-tienda-maxi-en-san-luis-y-lleva-realizadas-35-inauguraciones-en-el-ano",source:"El Diario de la República"},{tag:"Obra · 2025",title:"Avanza la construcción del Carrefour Maxi y el centro comercial con 50 locales",excerpt:"El gobernador Claudio Poggi recorrió el predio de la ZAC y destacó la inversión de USD 15M que generará 100 empleos directos. El proyecto incluye un galpón de 5.000 m² con paneles solares que cubrirán el 50% del consumo energético.",date:"9 Julio 2025",sortDate:"2025-07-09",img:"https://www.radiopopularsanluis.com.ar/galeria/fotos/2025/07/09/l_1752084140.jpeg",url:"https://www.radiopopularsanluis.com.ar/provincia/avanza-la-construccion-del-centro-comercial-que-albergara-un-carrefour-mayorista-y-mas-de-50-locales-en-la-zona-sur-de-san-luis.htm",source:"Radio Popular San Luis"},{tag:"Apertura · 2023",title:"Con altas expectativas, se inauguró la ZAC, el primer polo comercial y logístico de San Luis",excerpt:"La iniciativa de Coraza reunió a 20 empresas en la zona sur de la ciudad sobre Ruta 3, kilómetro 1. El predio de 8 hectáreas ofrece construcción, terminaciones, herramientas, coworking y espacios de capacitación.",date:"19 Octubre 2023",sortDate:"2023-10-19",img:"https://static.elchorrillero.com/x/2023/10/IMG_3982-930x620.jpg",url:"https://elchorrillero.com/nota/2023/10/19/420853-con-altas-expectativas-se-inauguro-la-zac-el-primer-polo-comercial-y-logistico-de-san-luis/amp/",source:"El Chorrillero"}];export{a as n};
